{"type": "post", "post": {"team": "cybersecurity", "channel": "training_updates", "user": "emily_patel", "message": "Thanks for the reminder, John. I'll make sure to go through the material today.", "created_at": 1620500000005}}
{"type": "post", "post": {"team": "it_operations", "channel": "service_desk", "user": "jane_doe", "message": "Sure, Emily. I'll get in touch with the server team and keep you updated.", "created_at": 1620500000006}}
